import React, { useState } from 'react';
import { Routes, Route, Link, useLocation } from 'react-router-dom';
import Home from './pages/Home';
import Clientes from './pages/Clientes';
import Categorias from './pages/Categorias';
import NovaOS from './pages/NovaOS';
import Relatorios from './pages/Relatorios';
import DetalhesOS from './pages/DetalhesOS';
import EditarOS from './pages/EditarOS';

function NavBar() {
  const location = useLocation();
  const [menuOpen, setMenuOpen] = useState(false);

  const toggleMenu = () => setMenuOpen(!menuOpen);

  return (
    <nav style={{
      background: 'linear-gradient(135deg, #1e3c72 0%, #2a5298 100%)',
      padding: '0.8rem 1.5rem',
      boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
      position: 'sticky',
      top: 0,
      zIndex: 1000,
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'space-between',
      flexWrap: 'wrap'
    }}>
      <div style={{ fontWeight: 'bold', fontSize: '1.5rem', color: 'white', letterSpacing: '1px' }}>
        🛠️ mwrSistema
      </div>
      <div className="menu-icon" onClick={toggleMenu} style={{ fontSize: '1.8rem', color: 'white', cursor: 'pointer' }}>
        ☰
      </div>
      <div className={`nav-links ${menuOpen ? 'open' : ''}`} style={{ display: 'flex', gap: '0.8rem', alignItems: 'center' }}>
        <NavLink to="/" label="🏠 Home" location={location} />
        <NavLink to="/clientes" label="👥 Clientes" location={location} />
        <NavLink to="/categorias" label="📂 Categorias" location={location} />
        <NavLink to="/nova-os" label="➕ Nova OS" location={location} />
        <NavLink to="/relatorios" label="📊 Relatórios" location={location} />
      </div>
    </nav>
  );
}

function NavLink({ to, label, location }) {
  const isActive = location.pathname === to;
  return (
    <Link to={to} style={{
      textDecoration: 'none',
      color: 'white',
      fontWeight: isActive ? 'bold' : '500',
      backgroundColor: isActive ? 'rgba(255,255,255,0.2)' : 'transparent',
      padding: '0.5rem 1rem',
      borderRadius: '40px',
      transition: '0.3s',
      whiteSpace: 'nowrap'
    }} onMouseEnter={e => e.target.style.backgroundColor = 'rgba(255,255,255,0.3)'}
      onMouseLeave={e => !isActive && (e.target.style.backgroundColor = 'transparent')}>
      {label}
    </Link>
  );
}

function App() {
  return (
    <div style={{ minHeight: '100vh', backgroundColor: '#f4f6f9' }}>
      <NavBar />
      <div style={{ padding: '1rem', maxWidth: '1400px', margin: '0 auto' }}>
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/clientes" element={<Clientes />} />
          <Route path="/categorias" element={<Categorias />} />
          <Route path="/nova-os" element={<NovaOS />} />
          <Route path="/relatorios" element={<Relatorios />} />
          <Route path="/os/:id" element={<DetalhesOS />} />
          <Route path="/os/editar/:id" element={<EditarOS />} />
        </Routes>
      </div>
    </div>
  );
}

export default App;
